  BookingsModel.fromJson(dynamic json) {
    _success = json['success'];
    _message = json['message'];
    if (json['data'] != null) {
      _data = [];
      json['data'].forEach((v) {
        _data?.add(BookingList.fromJson(v));
      });
    }
    _total = json['total'];
    _page = json['page'];
    _limit = json['limit'];
  }
